import { writeFileSync } from 'fs'
import path from 'path'
import {
  migrationRedirects,
  detectRedirectChains,
  normalizeRedirectPath,
} from '../lib/migration-redirects.mjs'

const OUTPUT = path.resolve('public/_redirects')

const chains = detectRedirectChains(migrationRedirects)
if (chains.length > 0) {
  console.error('Redirect chains detected (fix before deploy):')
  for (const chain of chains) {
    console.error(`  ${chain.join(' → ')}`)
  }
  process.exit(1)
}

/** @type {string[]} */
const lines = [
  '# Auto-generated by scripts/generate-redirects.mjs: do not edit by hand.',
  '# Regenerate: npm run generate:redirects',
  '#',
  '# WordPress → Next.js migration (301 permanent redirects)',
  '',
]

for (const { from, to, reason } of migrationRedirects) {
  const source = normalizeRedirectPath(from)
  const destination = normalizeRedirectPath(to)
  lines.push(`# ${reason}`)
  lines.push(`${source} ${destination} 301`)
  if (source !== '/') {
    lines.push(`${source}/ ${destination} 301`)
  }
  lines.push('')
}

writeFileSync(OUTPUT, lines.join('\n').trimEnd() + '\n', 'utf-8')
console.log(`Wrote ${migrationRedirects.length} redirects (${migrationRedirects.length * 2 - 1} rules) to public/_redirects`)
